66	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
67	const COMPONENT_TYPES = ["rune", "moonstone"];
68	const BLOCK_SIZE = 3;
69	const BLOCK_PREMIUM = 60;
70	const CURSE_SURCHARGE_RATE = 0.5;
71	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
72	const HIGH_ENCHANTMENT_THRESHOLD = 5;
73	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
74	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
75	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
76	
77	const BASE_PREMIUMS: Record<string, number> = {
78	  sword: 100,
79	  amulet: 60,
80	  staff: 80,
81	  potion: 40,
82	  rune: 25,
83	  moonstone: 25,
84	};
85	
86	const isComponent = (item: Item): boolean =>
87	  COMPONENT_TYPES.includes(item.type);
88	
89	const calculateItemPremium = (item: Item): number => {
90	  const base = BASE_PREMIUMS[item.type] ?? 0;
91	  let premium = base;
92	  if (item.cursed) {
93	    premium += base * CURSE_SURCHARGE_RATE;
94	  }
95	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
96	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
97	  }
98	  return premium;
99	};
100	
101	const calculateComponentPremium = (
102	  componentCounts: Record<string, number>,
103	): number => {
104	  let total = 0;
105	  for (const [type, count] of Object.entries(componentCounts)) {
106	    total +=
107	      count === BLOCK_SIZE
108	        ? BLOCK_PREMIUM
109	        : count * (BASE_PREMIUMS[type] ?? 0);
110	  }
111	  return total;
112	};
113	
114	const countByType = (items: { type: string }[], typeKey: "type" = "type"): Record<string, number> => {
115	  const counts: Record<string, number> = {};
116	  for (const item of items) {
117	    const key = item[typeKey];
118	    counts[key] = (counts[key] ?? 0) + 1;
119	  }
120	  return counts;
121	};
122	
123	const roundUpPremium = (value: number): number =>
124	  Math.ceil(parseFloat(value.toFixed(10)));
125	
126	const roundDownPayout = (value: number): number =>
127	  Math.floor(parseFloat(value.toFixed(10)));
128	
129	const processQuote = (
130	  step: QuoteStep,
131	  customer: { yearsWithMHPCO: number },
132	  quoteCount: number,
133	): { result: QuoteResult; policy: Omit<Policy, "remainingCap"> & { insuranceSum: number } } => {
134	  const componentCounts: Record<string, number> = {};
135	  let itemTotal = 0;
136	  let policyBase = 0;
137	  let insuranceSum = 0;
138	
139	  for (const item of step.items) {
140	    if (!(item.type in BASE_PREMIUMS)) {
141	      throw new Error(`Unknown item type: ${item.type}`);
142	    }
143	    insuranceSum += INSURANCE_VALUES[item.type] ?? 0;
144	    if (isComponent(item)) {
145	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
146	    } else {
147	      itemTotal += calculateItemPremium(item);
148	      policyBase += BASE_PREMIUMS[item.type] ?? 0;
149	    }
150	  }
151	
152	  const componentPremium = calculateComponentPremium(componentCounts);
153	  itemTotal += componentPremium;
154	  policyBase += componentPremium;
155	
156	  let totalBeforeFee = itemTotal;
157	
158	  // Policy-wide modifiers (all percentages of policyBase)
159	  totalBeforeFee += policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
160	
161	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
162	    totalBeforeFee -= policyBase * LOYALTY_DISCOUNT_RATE;
163	  }
164	
165	  if (quoteCount > 1) {
166	    totalBeforeFee -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
167	  }
168	
169	  const finalPremium = totalBeforeFee + PROCESSING_FEE;
170	
171	  return {
172	    result: { premium: roundUpPremium(finalPremium) },
173	    policy: { items: step.items, insuranceSum },
174	  };
175	};
176	
177	const validateDamages = (damages: Damage[], policyItems: Item[]): void => {
178	  const damageCounts = countByType(damages.map((d) => ({ type: d.itemType })));
179	  const insuredCounts = countByType(policyItems);
180	
181	  for (const [type, count] of Object.entries(damageCounts)) {
182	    if (count > (insuredCounts[type] ?? 0)) {
183	      throw new Error(`More damages of type "${type}" than items insured`);
184	    }
185	  }
186	};
187	
188	const processClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
189	  validateDamages(step.incident.damages, policy.items);
190	
191	  let totalPayout = 0;
192	  for (const damage of step.incident.damages) {
193	    const item = policy.items.find((i) => i.type === damage.itemType);
194	    if (!item) {
195	      throw new Error(`Damage for item type "${damage.itemType}" not in policy`);
196	    }
197	    if (damage.amount < 0) {
198	      throw new Error(`Negative damage amount: ${damage.amount}`);
199	    }
200	    let reimbursement = damage.amount;
201	
202	    if ((item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {
203	      reimbursement = reimbursement * CLAIM_HIGH_ENCHANTMENT_RATE;
204	    }
205	
206	    const payout = Math.max(0, reimbursement - DEDUCTIBLE);
207	    totalPayout += payout;
208	  }
209	
210	  totalPayout = Math.min(totalPayout, policy.remainingCap);
211	  totalPayout = roundDownPayout(totalPayout);
212	  policy.remainingCap -= totalPayout;
213	
214	  return { payout: totalPayout, remainingCap: policy.remainingCap };
215	};
216	
217	export const processScenario = (scenario: Scenario): ScenarioOutput => {
218	  let quoteCount = 0;
219	  const policies: Map<number, Policy> = new Map();
220	
221	  const results = scenario.steps.map((step, stepIndex) => {
222	    if (step.op === "quote") {
223	      quoteCount++;
224	      const { result, policy } = processQuote(step, scenario.customer, quoteCount);
225	      policies.set(stepIndex, {
226	        ...policy,
227	        remainingCap: policy.insuranceSum * 2,
228	      });
229	      return result;
230	    } else {
231	      const policy = policies.get(step.policy)!;
232	      return processClaim(step, policy);
233	    }
234	  });
235	
236	  return { results };
237	};
